import { GuestRequest } from "@/src/types";

// Setup global request object to persist data across Next.js dev server hot reloads
const globalForRequests = global as unknown as {
  requests: GuestRequest[];
  subscribers: Array<(payload: string) => void>;
};

if (!globalForRequests.requests) {
  globalForRequests.requests = [
    {
      id: "req-1",
      roomId: "302",
      items: [
        { id: "towels", emoji: "🛁", label: "Fresh Towels", description: "Soft & fluffy, right away" }
      ],
      status: "PENDING",
      createdAt: new Date(Date.now() - 2 * 60 * 1000).toISOString(), // 2 mins ago
      updatedAt: new Date(Date.now() - 2 * 60 * 1000).toISOString(),
      seenByStaff: false,
    },
    {
      id: "req-2",
      roomId: "105",
      items: [
        { id: "toiletries", emoji: "🪥", label: "Toiletries Kit", description: "Toothbrush, paste & more" },
        { id: "soap", emoji: "🧴", label: "Shampoo/Soap", description: "Top up your bathroom" }
      ],
      customText: "Please bring 2 extra conditioner bottles as well. Thank you!",
      status: "IN_PROGRESS",
      createdAt: new Date(Date.now() - 12 * 60 * 1000).toISOString(), // 12 mins ago
      updatedAt: new Date(Date.now() - 8 * 60 * 1000).toISOString(),
      seenByStaff: true,
    },
    {
      id: "req-3",
      roomId: "217",
      items: [
        { id: "blanket", emoji: "❄️", label: "Extra Blanket", description: "Stay warm tonight" }
      ],
      status: "ACKNOWLEDGED",
      createdAt: new Date(Date.now() - 18 * 60 * 1000).toISOString(), // 18 mins ago (acknowledged/pending)
      updatedAt: new Date(Date.now() - 17 * 60 * 1000).toISOString(),
      seenByStaff: true,
    },
    {
      id: "req-4",
      roomId: "410",
      items: [
        { id: "pillow", emoji: "🛏", label: "Extra Pillow", description: "For a better night's rest" }
      ],
      status: "DONE",
      createdAt: new Date(Date.now() - 45 * 60 * 1000).toISOString(), // 45 mins ago
      updatedAt: new Date(Date.now() - 30 * 60 * 1000).toISOString(),
      seenByStaff: true,
    }
  ];
}

if (!globalForRequests.subscribers) {
  globalForRequests.subscribers = [];
}

export const db = {
  getRequests() {
    return globalForRequests.requests;
  },

  setRequests(newRequests: GuestRequest[]) {
    globalForRequests.requests = newRequests;
  },

  addRequest(roomId: string, items: any[], customText?: string) {
    const newRequest: GuestRequest = {
      id: "req-" + Date.now(),
      roomId,
      items,
      customText,
      status: "PENDING",
      createdAt: new Date().toISOString(),
      updatedAt: new Date().toISOString(),
      seenByStaff: false,
    };
    globalForRequests.requests.unshift(newRequest);
    this.broadcast("CREATE", newRequest);
    return newRequest;
  },

  updateRequest(id: string, updates: Partial<GuestRequest>) {
    const idx = globalForRequests.requests.findIndex((r) => r.id === id);
    if (idx !== -1) {
      const updated = {
        ...globalForRequests.requests[idx],
        ...updates,
        updatedAt: new Date().toISOString(),
      };
      globalForRequests.requests[idx] = updated;
      this.broadcast("UPDATE", updated);
      return updated;
    }
    return null;
  },

  markAllSeen() {
    globalForRequests.requests = globalForRequests.requests.map((r) => ({
      ...r,
      seenByStaff: true,
    }));
    this.broadcast("MARK_SEEN", null);
  },

  subscribe(callback: (payload: string) => void) {
    globalForRequests.subscribers.push(callback);
    return () => {
      globalForRequests.subscribers = globalForRequests.subscribers.filter((cb) => cb !== callback);
    };
  },

  broadcast(type: string, data: any) {
    const payload = JSON.stringify({ type, data });
    globalForRequests.subscribers.forEach((cb) => cb(payload));
  }
};
